    if (source === target) return 0;

    // 1. Build Adjacency List
    const adj = Array(n).fill(0).map(() => []);
    for (const [u, v, w] of edges) {
        adj[u].push({ neighbor: v, weight: w });
        adj[v].push({ neighbor: u, weight: w });
    }

    /**
     * Checks if a path exists from source to target using at most k heavy edges 
     * given the threshold T.
     * Heavy edge if weight > T.
     * Uses Dijkstra's algorithm where cost = heavy edge count (0 or 1).
     * @param {number} T - The threshold.
     * @returns {boolean} True if a valid path exists, false otherwise.
     */
    const can_reach = (T) => {
        // D[i] stores the minimum number of heavy edges to reach node i.
        // Since N <= 1000, we initialize with K+1 or Infinity.
        const INF = k + 1;
        const D = Array(n).fill(INF);

        D[source] = 0;

        // PQ stores [heavy_count, node]
        const pq = new MinPriorityQueue();
        pq.enqueue([0, source]);

        while (!pq.isEmpty()) {
            const [h, u] = pq.dequeue();

            if (h > D[u]) {
                continue;
            }

            if (u === target) {
                // Since Dijkstra explores paths in increasing order of heavy_count,
                // the first time we reach target, we found the minimum count.
                return true; 
            }

            // Optimization: if current count already exceeds K, we don't need to explore further from here.
            // Although D[u] should prevent this if we strictly check D[u] <= K before enqueueing, 
            // checking h <= K here is safer if we didn't prune before.
            if (h > k) continue;


            for (const edge of adj[u]) {
                const v = edge.neighbor;
                const w = edge.weight;

                // Cost is 1 if heavy (w > T), 0 otherwise.
                const cost = (w > T) ? 1 : 0;

                const h_new = h + cost;

                if (h_new < D[v]) {
                    D[v] = h_new;
                    // Only enqueue if the new path is potentially useful (i.e., doesn't immediately exceed K)
                    if (h_new <= k) {
                         pq.enqueue([h_new, v]);
                    }
                }
            }
        }

        // If the loop finishes without hitting the target (or if D[target] > K), return false.
        return D[target] <= k;
    };


    // 2. Binary Search for the minimum threshold T
    // Search space: [L, R). We search up to 10^9 + 1.
    let L = 0;
    // Max possible weight is 10^9. If T = 10^9 + 1, all edges are light (cost 0).
    let R = 1000000001 + 1; 
    let min_T = -1;

    while (L < R) {
        // Calculate M safely
        const M = L + Math.floor((R - L) / 2);

        if (can_reach(M)) {
            // M works. Store it as a potential answer and try for a smaller threshold.
            min_T = M;
            R = M;
        } else {
            // M is too low (or unreachable). Need a higher threshold.
            L = M + 1;
        }
    }

    return min_T;
}
